20	const PROCESSING_FEE = 5;
21	// Premiums are accumulated in tenths of a gold piece so we can apply
22	// fractional surcharges/discounts with integer math and round once at the end
23	// (avoids floating-point artifacts like 100 * 1.1 = 110.00000000000001).
24	const TENTHS_PER_UNIT = 10;
25	const FIRST_INSURANCE_TENTHS = 1;
26	
27	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
28	  sword: 100,
29	  amulet: 60,
30	  staff: 80,
31	  potion: 40,
32	  rune: 25,
33	};
34	
35	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
36	const BLOCK_SIZE = 3;
37	const BLOCK_BASE_PREMIUM = 60;
38	
39	const basePremium = (item: Item): number => BASE_PREMIUM_BY_TYPE[item.type] ?? 0;
40	
41	const itemsBasePremium = (items: Item[]): number => {
42	  const components: Record<string, Item[]> = {};
43	  const mains: Item[] = [];
44	  for (const item of items) {
45	    if (COMPONENT_TYPES.has(item.type)) {
46	      (components[item.type] ??= []).push(item);
47	    } else {
48	      mains.push(item);
49	    }
50	  }
51	  let total = mains.reduce((sum, item) => sum + basePremium(item), 0);
52	  for (const group of Object.values(components)) {
53	    if (group.length === BLOCK_SIZE) {
54	      total += BLOCK_BASE_PREMIUM;
55	    } else {
56	      total += group.reduce((sum, item) => sum + basePremium(item), 0);
57	    }
58	  }
59	  return total;
60	};
61	
62	const roundUpTenthsToUnits = (tenths: number): number => Math.ceil(tenths / TENTHS_PER_UNIT);
63	
64	const quote = (step: QuoteStep): QuoteResult => {
65	  const baseTotal = itemsBasePremium(step.items);
66	  const totalTenths = baseTotal * (TENTHS_PER_UNIT + FIRST_INSURANCE_TENTHS);
67	  return { premium: roundUpTenthsToUnits(totalTenths) + PROCESSING_FEE };
68	};
69	
70	export const runScenario = (scenario: Scenario): ScenarioResult => {
71	  return { results: scenario.steps.map(quote) };
72	};
